-- bus_stops_seed.sql
-- Generated from bus_stops.csv  |  1331 unique stops  |  Greater Tunis area
-- Run with:  psql -h localhost -U navuser -d navdb -f bus_stops_seed.sql

BEGIN;

CREATE TABLE IF NOT EXISTS transit_stops (
  id                  VARCHAR(50)  PRIMARY KEY,
  name                VARCHAR(255) NOT NULL,
  description         TEXT,
  location            geometry(Point, 4326) NOT NULL,
  location_type       INTEGER DEFAULT 0,
  parent_station_id   VARCHAR(50),
  wheelchair_boarding INTEGER DEFAULT 0,
  platform_code       VARCHAR(20),
  timezone            VARCHAR(50)
);

CREATE INDEX IF NOT EXISTS transit_stops_location_gist ON transit_stops USING GIST (location);
CREATE INDEX IF NOT EXISTS transit_stops_name_idx      ON transit_stops (name);

ON CONFLICT (id) DO UPDATE SET
  name     = EXCLUDED.name,
  location = EXCLUDED.location;

COMMIT;
-- Inserted/updated 1331 stops
